	@Override
	public QueryJoinOptimizer getOptimizer() {
		return new QueryJoinOptimizer(new EvaluationStatistics(), new EmptyTripleSource());
	}

	private TupleExpr findLeaf(TupleExpr expr) {
		if (expr instanceof UnaryTupleOperator) {
			return findLeaf(((UnaryTupleOperator) expr).getArg());
		} else if (expr instanceof BinaryTupleOperator) {
			return findLeaf(((BinaryTupleOperator) expr).getLeftArg());
		} else {
			return expr;
		}
	}

	private static List<TupleExpr> flattenJoinLeaves(TupleExpr tupleExpr) {
		ArrayList<TupleExpr> leaves = new ArrayList<>();
		collectJoinLeaves(tupleExpr, leaves);
		return leaves;
	}

	private static void collectJoinLeaves(TupleExpr tupleExpr, List<TupleExpr> leaves) {
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			collectJoinLeaves(join.getLeftArg(), leaves);
			collectJoinLeaves(join.getRightArg(), leaves);
			return;
		}

		leaves.add(tupleExpr);
	}

	void testOptimizer(String expectedQuery, String actualQuery)
			throws MalformedQueryException, UnsupportedQueryLanguageException {
		ParsedQuery pq = QueryParserUtil.parseQuery(QueryLanguage.SPARQL, actualQuery, null);
		QueryJoinOptimizer opt = getOptimizer();
		QueryRoot optRoot = new QueryRoot(pq.getTupleExpr());
		opt.optimize(optRoot, null, null);

		ParsedQuery expectedParsedQuery = QueryParserUtil.parseQuery(QueryLanguage.SPARQL, expectedQuery, null);
		QueryRoot root = new QueryRoot(expectedParsedQuery.getTupleExpr());
		assertQueryModelTrees(root, optRoot);
	}

	private void assertQueryModelTrees(QueryModelNode expected, QueryModelNode actual) {
		assertEquals(expected, actual);
	}

	class JoinFinder extends AbstractQueryModelVisitor<RuntimeException> {

		private Join join;

		@Override
		public void meet(Join join) {
			this.join = join;
		}

		public Join getJoin() {
			return join;
		}
	}

	class StatementFinder extends AbstractQueryModelVisitor<RuntimeException> {

		private final List<StatementPattern> statements = new ArrayList<>();

		@Override
		public void meet(StatementPattern st) {
			this.statements.add(st);
		}

		public List<StatementPattern> getStatements() {
			return statements;
		}
	}

	private static List<TupleExpr> flattenJoinLeavesKeepingScopeBarriers(TupleExpr tupleExpr) {
		ArrayList<TupleExpr> leaves = new ArrayList<>();
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			collectJoinLeavesKeepingScopeBarriers(join.getLeftArg(), leaves);
			collectJoinLeavesKeepingScopeBarriers(join.getRightArg(), leaves);
		} else {
			collectJoinLeavesKeepingScopeBarriers(tupleExpr, leaves);
		}
		return leaves;
	}

	private static void collectJoinLeavesKeepingScopeBarriers(TupleExpr tupleExpr, List<TupleExpr> leaves) {
		if (tupleExpr instanceof Join && !TupleExprs.isVariableScopeChange(tupleExpr)
				&& !TupleExprs.containsExtension(tupleExpr) && !TupleExprs.containsSubquery(tupleExpr)) {
			Join join = (Join) tupleExpr;
			collectJoinLeavesKeepingScopeBarriers(join.getLeftArg(), leaves);
			collectJoinLeavesKeepingScopeBarriers(join.getRightArg(), leaves);
			return;
		}

		leaves.add(tupleExpr);
	}

	private static List<String> leadingPrefixPredicates(TupleExpr tupleExpr, int limit) {
		TupleExpr prefix = flattenJoinLeavesKeepingScopeBarriers(unwrapQueryRoot(tupleExpr)).get(0);
		while (prefix instanceof Filter) {
			prefix = unwrapQueryRoot(((Filter) prefix).getArg());
		}
		ArrayList<String> predicates = new ArrayList<>();
		unwrapQueryRoot(prefix).visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern statementPattern) {
				predicates.add(statementPattern.getPredicateVar().getValue().stringValue());
			}
		});
		return predicates.stream().limit(limit).collect(Collectors.toList());
	}

	private static List<String> flattenedLeafPredicates(TupleExpr tupleExpr) {
		return flattenJoinLeavesKeepingScopeBarriers(unwrapQueryRoot(tupleExpr)).stream()
				.map(QueryJoinOptimizerTest::firstStatementPatternPredicate)
				.filter(predicate -> predicate != null)
				.collect(Collectors.toList());
	}

	private static String firstStatementPatternPredicate(TupleExpr tupleExpr) {
		ArrayList<String> predicates = new ArrayList<>();
		unwrapQueryRoot(tupleExpr).visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern statementPattern) {
				if (predicates.isEmpty()) {
					predicates.add(statementPattern.getPredicateVar().getValue().stringValue());
				}
			}
		});
		return predicates.isEmpty() ? null : predicates.get(0);
	}

	private static TupleExpr unwrapQueryRoot(TupleExpr tupleExpr) {
		while (tupleExpr instanceof QueryRoot || tupleExpr instanceof Projection) {
			if (tupleExpr instanceof QueryRoot) {
				tupleExpr = ((QueryRoot) tupleExpr).getArg();
			} else {
				tupleExpr = ((Projection) tupleExpr).getArg();
			}
		}
		return tupleExpr;
	}

	private static QueryRoot optimizeWithStatistics(String query, EvaluationStatistics statistics) {
		QueryRoot root = new QueryRoot(QueryParserUtil.parseQuery(QueryLanguage.SPARQL, query, null).getTupleExpr());
		new QueryJoinOptimizer(statistics, new EmptyTripleSource()).optimize(root, null, null);
		return root;
	}

	private static List<QueryModelNode> optimizerAnnotatedNodes(QueryModelNode root) {
		List<QueryModelNode> nodes = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) throws RuntimeException {
				if (node.getStringMetricActual("optimizer.strategy") != null
						|| node.getStringMetricActual("optimizer.decisionTrace") != null) {
					nodes.add(node);
				}
				super.meetNode(node);
			}
		});
		return nodes;
	}

	private static Filter firstFilter(QueryModelNode root) {
		List<Filter> filters = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter filter) throws RuntimeException {
				filters.add(filter);
				super.meet(filter);
			}
		});
		assertThat(filters).isNotEmpty();
		return filters.get(0);
	}

	private static List<BindingSetAssignment> bindingSetAssignments(QueryModelNode root, String bindingName) {
		List<BindingSetAssignment> assignments = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(BindingSetAssignment assignment) throws RuntimeException {
				if (assignment.getBindingNames().contains(bindingName)) {
					assignments.add(assignment);
				}
				super.meet(assignment);
			}
		});
		return assignments;
	}

	private Object buildJoinVisitor(QueryJoinOptimizer optimizer) throws Exception {
		Class<?> joinVisitorClass = Class
				.forName("org.eclipse.rdf4j.query.algebra.evaluation.optimizer.QueryJoinOptimizer$JoinVisitor");
		Constructor<?> constructor = joinVisitorClass.getDeclaredConstructor(QueryJoinOptimizer.class);
		constructor.setAccessible(true);
		return constructor.newInstance(optimizer);
	}

	@SuppressWarnings("unchecked")
	private List<TupleExpr> invokeGetJoinArgs(QueryJoinOptimizer optimizer, TupleExpr tupleExpr) throws Exception {
		Object joinVisitor = buildJoinVisitor(optimizer);
		Method getJoinArgs = joinVisitor.getClass().getDeclaredMethod("getJoinArgs", TupleExpr.class, List.class);
		getJoinArgs.setAccessible(true);
		return (List<TupleExpr>) getJoinArgs.invoke(joinVisitor, tupleExpr, new ArrayList<TupleExpr>());
	}

	@SuppressWarnings("unchecked")
	private List<TupleExpr> invokeCollectJoinArgsForOrdering(QueryJoinOptimizer optimizer, Join join) throws Exception {
		Object joinVisitor = buildJoinVisitor(optimizer);
		Method collectJoinArgsForOrdering = joinVisitor.getClass()
				.getDeclaredMethod("collectJoinArgsForOrdering",
						Join.class, List.class);
		collectJoinArgsForOrdering.setAccessible(true);
		List<TupleExpr> joinArgs = new ArrayList<>();
		collectJoinArgsForOrdering.invoke(joinVisitor, join, joinArgs);
		return joinArgs;
	}

	private static StatementPattern statementPattern(String subjectVarName, String objectVarName, String predicateIri) {
		return new StatementPattern(Var.of(subjectVarName),
				Var.of(subjectVarName + "Predicate", VF.createIRI(predicateIri)),
				Var.of(objectVarName));
	}

	private static Filter filter(TupleExpr arg, String leftVarName, String rightVarName) {
		return new Filter(arg, new Compare(Var.of(leftVarName), Var.of(rightVarName), CompareOp.NE));
	}

	private static BindingSetAssignment bindingSetAssignment(String varName, String localName) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		QueryBindingSet bindingSet = new QueryBindingSet();
		bindingSet.addBinding(varName, VF.createIRI(ex(localName)));
		assignment.setBindingSets(List.<BindingSet>of(bindingSet));
		return assignment;
	}

	private static BindingSetAssignment bindingSetAssignment(Map<String, String> iriBindings) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		QueryBindingSet bindingSet = new QueryBindingSet();
		iriBindings.forEach((name, iri) -> bindingSet.addBinding(name, VF.createIRI(iri)));
		assignment.setBindingSets(List.<BindingSet>of(bindingSet));
		return assignment;
	}

