	private static final class PairwiseJoinStatistics extends EvaluationStatistics {
		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public boolean supportsFilterSelectivityCosting() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				return getStatementCardinality((StatementPattern) expr);
			}

			if (expr instanceof Join) {
				return getJoinCardinality((Join) expr);
			}

			return super.getCardinality(expr);
		}

		private double getStatementCardinality(StatementPattern pattern) {
			String predicate = predicate(pattern);
			if ("ex:pA".equals(predicate)) {
				return 2;
			}
			if ("ex:pB".equals(predicate)) {
				return 3;
			}
			if ("ex:pC".equals(predicate)) {
				return 4;
			}
			return 10;
		}

		private double getJoinCardinality(Join join) {
			String left = predicate(join.getLeftArg());
			String right = predicate(join.getRightArg());

			if (left == null || right == null) {
				return super.getCardinality(join);
			}

			if ((left.equals("ex:pA") && right.equals("ex:pB")) || (left.equals("ex:pB") && right.equals("ex:pA"))) {
				return 100;
			}
			if ((left.equals("ex:pA") && right.equals("ex:pC")) || (left.equals("ex:pC") && right.equals("ex:pA"))) {
				return 80;
			}
			if ((left.equals("ex:pB") && right.equals("ex:pC")) || (left.equals("ex:pC") && right.equals("ex:pB"))) {
				return 5;
			}

			return super.getCardinality(join);
		}

		private String predicate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Var predicateVar = ((StatementPattern) expr).getPredicateVar();
				if (predicateVar != null && predicateVar.hasValue()) {
					return predicateVar.getValue().stringValue();
				}
			}
			return null;
		}
	}

	private static final class ScopedStatistics extends EvaluationStatistics implements QueryOptimizationScopeProvider {
		private int openedScopes;
		private int closedScopes;
		private int activeScopes;
		private int cardinalityCalls;

		@Override
		public QueryOptimizationScope beginQueryOptimizationScope() {
			openedScopes++;
			activeScopes++;
			return () -> {
				closedScopes++;
				activeScopes--;
			};
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			cardinalityCalls++;
			assertTrue(activeScopes > 0, "Cardinality estimation should run inside the optimization scope");
			return super.getCardinality(expr);
		}
	}

	private static final class CardinalityCountingStatistics extends EvaluationStatistics {
		private int filterCardinalityCalls;

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof Filter) {
				filterCardinalityCalls++;
			}
			return super.getCardinality(expr);
		}
	}

	private static final class ParsedQueryPairwiseJoinStatistics extends EvaluationStatistics {
		private final Map<String, Double> joinCosts;

		private ParsedQueryPairwiseJoinStatistics(Map<String, Double> joinCosts) {
			this.joinCosts = joinCosts;
		}

		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof Join) {
				Join join = (Join) expr;
				String left = tupleExprKey(join.getLeftArg());
				String right = tupleExprKey(join.getRightArg());
				if (left != null && right != null) {
					return joinCosts.getOrDefault(pairKey(left, right), 1000.0d);
				}
				return 1000.0d;
			}

			if (expr instanceof StatementPattern) {
				return 10.0d;
			}

			return super.getCardinality(expr);
		}

		@Override
		public FilterPassEstimate estimateFilterPass(Filter filter) {
			if (filter.getCondition() instanceof Compare) {
				return new FilterPassEstimate(0.25d, FilterPassEstimate.Source.HEURISTIC);
			}
			return new FilterPassEstimate(-1.0d, FilterPassEstimate.Source.UNKNOWN);
		}

		private String predicate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				return getPredicateValue(expr);
			}
			return null;
		}
	}

	private static final class PlannerStatistics extends EvaluationStatistics implements JoinOrderPlanner {
		private final List<TupleExpr> orderedArgs;
		private final List<TupleExpr> expectedArgs;
		private final double estimatedFinalRows;
		private final double statementCardinality;
		private List<JoinOrderPlanner.FilterConstraint> filterConstraints = List.of();
		private int planCalls;
		private int joinCardinalityCalls;

		private PlannerStatistics(List<TupleExpr> orderedArgs) {
			this(orderedArgs, List.of(orderedArgs.get(2), orderedArgs.get(1), orderedArgs.get(0)));
		}

		private PlannerStatistics(List<TupleExpr> orderedArgs, List<TupleExpr> expectedArgs) {
			this(orderedArgs, expectedArgs, 1.0d, 10.0d);
		}

		private PlannerStatistics(List<TupleExpr> orderedArgs, List<TupleExpr> expectedArgs,
				double estimatedFinalRows, double statementCardinality) {
			this.orderedArgs = orderedArgs;
			this.expectedArgs = expectedArgs;
			this.estimatedFinalRows = estimatedFinalRows;
			this.statementCardinality = statementCardinality;
		}

		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof Join) {
				joinCardinalityCalls++;
			}
			return statementCardinality;
		}

		@Override
		public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
				Algorithm algorithm) {
			planCalls++;
			assertThat(args).containsExactlyElementsOf(expectedArgs);
			return Optional.of(new JoinOrderPlan(orderedArgs, estimatedFinalRows, 1.0d));
		}

		@Override
		public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
				Algorithm algorithm, List<JoinOrderPlanner.FilterConstraint> deferredFilters) {
			filterConstraints = List.copyOf(deferredFilters);
			return planJoinOrder(args, initiallyBoundVars, algorithm);
		}
	}

